const source = $('Normalize Request').first().json;
const response = $input.first().json;
const productionPrompt = response.text || '';
if (!productionPrompt) throw new Error('Respons /api/generate kosong.');

const tags = Array.isArray(source.metadata.youtubeTags) ? source.metadata.youtubeTags : ['vidgen', 'automation', 'youtube'];
const youtubeTitle = source.metadata.youtubeTitle || source.title || 'Video VidGen';
const youtubeDescription = source.metadata.youtubeDescription || productionPrompt.slice(0, 4500);
const youtubeCategory = source.metadata.youtubeCategoryId || '27';
const privacyStatus = source.metadata.youtubePrivacyStatus || 'private';

return [{
  json: {
    ...source,
    productionPrompt,
    outputs: {
      productionPrompt,
      generatedAt: new Date().toISOString(),
      source: 'automation.maksitech.id/api/generate'
    },
    youtube: {
      title: youtubeTitle,
      description: youtubeDescription,
      tags,
      categoryId: youtubeCategory,
      privacyStatus
    }
  }
}];

return [{
  json: {
    ...$input.first().json,
    renderPayload: {
      jobId: $json.jobId,
      title: $json.youtube.title,
      topic: $json.title,
      category: $json.category,
      prompt: $json.productionPrompt,
      metadata: $json.metadata,
      callbackUrl: $json.callbackUrl,
      callbackSecret: $json.callbackSecret,
      requestedAt: new Date().toISOString()
    }
  }
}];

const source = $('Prepare Render Payload').first().json;
const renderResult = $input.first().json || {};
const finalVideoUrl = renderResult.finalVideoUrl || renderResult.videoUrl || '';

return [{
  json: {
    ...source,
    finalVideoUrl,
    shortVideoUrl: renderResult.shortVideoUrl || '',
    thumbnailUrl: renderResult.thumbnailUrl || '',
    outputs: {
      ...source.outputs,
      renderResponse: renderResult
    }
  }
}];

const source = $('Build Render Result').first().json;
const stdout = $input.first().json.stdout || '';
const localFilePath = (stdout.match(/LOCAL_FILE:(.+)/)?.[1] || '').trim();
if (!localFilePath) throw new Error('File video lokal gagal disiapkan untuk upload YouTube.');
return [{ json: { ...source, localFilePath } }];

const source = $('Parse Local File').first().json;
const yt = $input.first().json || {};
const videoId = yt.id || yt.videoId || '';
return [{
  json: {
    ...source,
    youtubeUrl: videoId ? `https://www.youtube.com/watch?v=${videoId}` : source.youtubeUrl || '',
    outputs: {
      ...source.outputs,
      youtubeResponse: yt
    },
    status: 'completed',
    message: videoId ? 'Render selesai dan video berhasil diupload ke YouTube.' : 'Render selesai. Upload YouTube tidak mengembalikan video ID.'
  }
}];

const source = $input.first().json;
return [{
  json: {
    ...source,
    status: 'completed',
    message: source.finalVideoUrl
      ? 'Render selesai. Upload YouTube dilewati karena konfigurasi publish dimatikan.'
      : 'Paket produksi selesai. Render dan upload YouTube belum dijalankan.'
  }
}];
